from collections import Counter
def best_pair(words):
    pairs=Counter()
    for w,freq in words.items():
        syms=w.split()
        for a,b in zip(syms,syms[1:]): pairs[(a,b)]+=freq
    return pairs.most_common(1)[0][0]
def merge(words, pair):
    bigram=' '.join(pair); joined=''.join(pair)
    return {w.replace(bigram, joined):f for w,f in words.items()}
words={'l o w':5,'l o w e r':2,'n e w e s t':6,'w i d e s t':3}
for _ in range(2):
    p=best_pair(words); words=merge(words,p); print('merged',p)
# merges 'e','s' (9x) then 'es','t' (9x) -> 'est' becomes a token
```

BPE starts from single characters and **greedily merges the most frequent adjacent pair** into a new symbol, repeating K times. Frequent sequences ('est', 'low') become single tokens; the vocab grows from characters toward whole words. After training, common words are one token and rare words split into known pieces — covering any string with a finite vocab.
